SELECT variable_id, COUNT(*) AS entry_count
FROM form_data
GROUP BY variable_id;

SELECT form_id, n
FROM form_data
WHERE group_id = 1;

SELECT COUNT(form_data_id)
FROM form_data
WHERE category_id = 1;

SELECT form_name, form_description
FROM forms
WHERE form_id = 0;

SELECT form_id, category_id, n
FROM form_data
WHERE group_id = (SELECT group_id FROM patient_groups WHERE group_name = 'MH');

SELECT DISTINCT group_name
FROM patient_groups
ORDER BY group_name;

SELECT form_name 
FROM forms 
ORDER BY form_name;
